class Solution:
    def splitListToParts(self, head: Optional[ListNode], k: int) -> List[Optional[ListNode]]:
        n = 0; cur = head
        while cur: n += 1; cur = cur.next
        width, rem = divmod(n, k)
        ans, cur = [], head
        for i in range(k):
            part = cur
            size = width + (1 if i < rem else 0)
            for _ in range(size - 1):
                if cur: cur = cur.next
            if cur:
                nxt = cur.next; cur.next = None; cur = nxt
            ans.append(part)
        return ans

