class Solution {
public:
    vector<ListNode*> splitListToParts(ListNode* head, int k) {
        int n=0; for(auto c=head;c;c=c->next) n++;
        int w=n/k, r=n%k;
        vector<ListNode*> ans(k);
        auto cur=head;
        for(int i=0;i<k;i++){
            ans[i]=cur;
            int sz=w+(i<r);
            for(int j=1;j<sz&&cur;j++) cur=cur->next;
            if(cur){ auto nxt=cur->next; cur->next=nullptr; cur=nxt; }
        }
        return ans;
    }
};

